import{_ as e,o as l,c as a,ag as r}from"./chunks/framework.DHfb4PWj.js";const p=JSON.parse('{"title":"实时协同系统","description":"","frontmatter":{},"headers":[],"relativePath":"interview/解决方案/实时协同系统/index.md","filePath":"interview/解决方案/实时协同系统/index.md"}'),s={name:"interview/解决方案/实时协同系统/index.md"};function o(n,t,i,d,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r(`<h1 id="实时协同系统" tabindex="-1">实时协同系统 <a class="header-anchor" href="#实时协同系统" aria-label="Permalink to &quot;实时协同系统&quot;">​</a></h1><h2 id="基础概念篇" tabindex="-1">基础概念篇 <a class="header-anchor" href="#基础概念篇" aria-label="Permalink to &quot;基础概念篇&quot;">​</a></h2><h2 id="q-实时协同编辑的核心技术挑战是什么" tabindex="-1">Q: 实时协同编辑的核心技术挑战是什么？ <a class="header-anchor" href="#q-实时协同编辑的核心技术挑战是什么" aria-label="Permalink to &quot;Q: 实时协同编辑的核心技术挑战是什么？&quot;">​</a></h2><p><strong>A:</strong></p><p>实时协同编辑的核心挑战是<strong>并发冲突问题</strong>：当多个用户几乎同时修改同一位置时（如 A 在开头插入文字，B 几乎同时删除了前几个字），系统必须保证：</p><ol><li><strong>每个用户的操作都不丢失</strong></li><li><strong>所有人最终看到完全一致的结果</strong>（最终一致性）</li></ol><p>业界主要有两种解决方案：<strong>OT（操作转换）</strong> 和 <strong>CRDT（无冲突复制数据类型）</strong>。</p><hr><h2 id="q-ot-操作转换-和-crdt-无冲突复制数据类型-的核心区别是什么" tabindex="-1">Q: OT（操作转换）和 CRDT（无冲突复制数据类型）的核心区别是什么？ <a class="header-anchor" href="#q-ot-操作转换-和-crdt-无冲突复制数据类型-的核心区别是什么" aria-label="Permalink to &quot;Q: OT（操作转换）和 CRDT（无冲突复制数据类型）的核心区别是什么？&quot;">​</a></h2><p><strong>A:</strong></p><p>两者代表了解决并发冲突的不同哲学：</p><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">OT（操作转换）</th><th style="text-align:left;">CRDT（无冲突复制数据类型）</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>核心思想</strong></td><td style="text-align:left;">将并发操作进行&quot;转换&quot;，使其在新状态下仍能正确执行</td><td style="text-align:left;">设计特殊数据结构，保证并发操作无需协调即可自动合并</td></tr><tr><td style="text-align:left;"><strong>架构依赖</strong></td><td style="text-align:left;"><strong>中心化</strong>，需要中央服务器接收、转换、广播操作</td><td style="text-align:left;"><strong>去中心化</strong>，客户端本地解决冲突，天然支持 P2P</td></tr><tr><td style="text-align:left;"><strong>离线支持</strong></td><td style="text-align:left;">对网络延迟敏感，离线支持较弱</td><td style="text-align:left;">高延迟容忍，天然支持离线编辑，网络恢复后自动同步</td></tr><tr><td style="text-align:left;"><strong>优势</strong></td><td style="text-align:left;">技术成熟稳定，是 Google Docs 等大型产品的基石</td><td style="text-align:left;">扩展性强，性能好，适合大规模用户和高并发场景</td></tr><tr><td style="text-align:left;"><strong>劣势</strong></td><td style="text-align:left;">扩展性受限，转换逻辑复杂，难以处理大量并发用户</td><td style="text-align:left;">数据结构复杂，实现难度高，可能有更大的存储/内存开销</td></tr><tr><td style="text-align:left;"><strong>典型代表</strong></td><td style="text-align:left;">Google Docs、ShareDB</td><td style="text-align:left;">Yjs、Automerge、Fugue</td></tr></tbody></table><blockquote><p>⚠️ <strong>前沿动态</strong>：剑桥大学教授 Martin Kleppmann 提出的 <strong>Eg-walker 算法</strong>尝试融合两者优点——拥有 CRDT 的轻量级内存和快速加载，同时具备 OT 快速合并长分支的能力，代表未来发展方向。</p></blockquote><hr><h2 id="技术选型篇" tabindex="-1">技术选型篇 <a class="header-anchor" href="#技术选型篇" aria-label="Permalink to &quot;技术选型篇&quot;">​</a></h2><h2 id="q-主流富文本编辑器框架有哪些-如何选择" tabindex="-1">Q: 主流富文本编辑器框架有哪些？如何选择？ <a class="header-anchor" href="#q-主流富文本编辑器框架有哪些-如何选择" aria-label="Permalink to &quot;Q: 主流富文本编辑器框架有哪些？如何选择？&quot;">​</a></h2><p><strong>A:</strong></p><p>现代主流编辑器均采用&quot;<strong>数据驱动</strong>&quot;架构（第三代编辑器）：将文档内容抽象为独立数据模型，再渲染到 DOM，从而实现高度可控性。</p><table tabindex="0"><thead><tr><th style="text-align:left;">编辑器</th><th style="text-align:left;">核心特点</th><th style="text-align:left;">协同能力</th><th style="text-align:left;">适用场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>ProseMirror</strong></td><td style="text-align:left;">功能强大、基于 Schema 设计，对文档结构有极致控制力</td><td style="text-align:left;">内置 <code>prosemirror-collab</code> 支持 OT；可通过 <code>y-prosemirror</code> 集成 Yjs</td><td style="text-align:left;">复杂应用，对性能和文档结构有极致要求，上层封装 <strong>Tiptap</strong> 更易上手</td></tr><tr><td style="text-align:left;"><strong>Slate</strong></td><td style="text-align:left;">插件化架构，所有功能均可作为插件，灵活性极高，与 React 深度绑定</td><td style="text-align:left;">不内置协同，需自行实现 OT 或集成 <code>slate-yjs</code></td><td style="text-align:left;">需要深度定制编辑体验的复杂 React 项目</td></tr><tr><td style="text-align:left;"><strong>Quill</strong></td><td style="text-align:left;">轻量、API 简洁，通过 Delta 格式表示内容，开箱即用</td><td style="text-align:left;">可通过 <code>quill-delta</code> 配合 ShareDB（OT）或 Yjs（CRDT）实现协同</td><td style="text-align:left;">快速集成、功能标准的场景，MVP 验证首选</td></tr></tbody></table><p><strong>选型建议</strong>：</p><ul><li>追求最强协同 + 离线支持 → <strong>ProseMirror/Tiptap + Yjs</strong></li><li>快速验证、简单需求 → <strong>Quill + Yjs/ShareDB</strong></li><li>React 深度定制 → <strong>Slate + Yjs</strong></li></ul><hr><h2 id="q-协同编辑中-yjs-和-sharedb-如何选择" tabindex="-1">Q: 协同编辑中 Yjs 和 ShareDB 如何选择？ <a class="header-anchor" href="#q-协同编辑中-yjs-和-sharedb-如何选择" aria-label="Permalink to &quot;Q: 协同编辑中 Yjs 和 ShareDB 如何选择？&quot;">​</a></h2><p><strong>A:</strong></p><p><strong>Yjs（CRDT 流派）：</strong></p><ul><li>高性能 CRDT 库，将文本、数组、Map 等转换为可无冲突合并的 CRDT 结构</li><li><strong>网络层无关</strong>，可与 WebSocket、WebRTC 等任意协议集成</li><li><strong>天生支持离线编辑</strong>和去中心化架构</li><li>生态极强：为 ProseMirror、Quill、CodeMirror 等几乎所有主流编辑器提供适配器</li></ul><p><strong>ShareDB（OT 流派）：</strong></p><ul><li>成熟的 OT 实时数据库同步框架，运行在 Node.js 后端</li><li>与 JSON 结构深度集成，与 MongoDB 配合默契，通常搭配 WebSocket</li><li><strong>基于中心化设计</strong>，对服务器依赖强，离线支持能力有限</li><li>适合已有 Node.js + MongoDB 后端、希望使用经过大量验证的 OT 方案的项目</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>推荐组合：</span></span>
<span class="line"><span>├── 新项目 / 要求离线 / 去中心化  →  Yjs</span></span>
<span class="line"><span>└── 已有 Node.js 后端 / 偏好 OT   →  ShareDB</span></span></code></pre></div><hr><h2 id="进阶实现篇" tabindex="-1">进阶实现篇 <a class="header-anchor" href="#进阶实现篇" aria-label="Permalink to &quot;进阶实现篇&quot;">​</a></h2><h2 id="q-实时协同系统有哪些进阶要点" tabindex="-1">Q: 实时协同系统有哪些进阶要点？ <a class="header-anchor" href="#q-实时协同系统有哪些进阶要点" aria-label="Permalink to &quot;Q: 实时协同系统有哪些进阶要点？&quot;">​</a></h2><p><strong>A:</strong></p><h3 id="_1-光标同步与用户感知" tabindex="-1">1. 光标同步与用户感知 <a class="header-anchor" href="#_1-光标同步与用户感知" aria-label="Permalink to &quot;1. 光标同步与用户感知&quot;">​</a></h3><p>除内容同步外，实时显示协作者的光标位置和文本选区同样关键。Yjs 提供了 <strong><code>awareness</code> 协议</strong>（基于 <code>y-protocols/awareness.js</code>），专门用于高效处理这类非文档内容的实时状态同步。</p><h3 id="_2-离线支持与版本管理" tabindex="-1">2. 离线支持与版本管理 <a class="header-anchor" href="#_2-离线支持与版本管理" aria-label="Permalink to &quot;2. 离线支持与版本管理&quot;">​</a></h3><ul><li><strong>离线</strong>：CRDT 的天然优势。利用浏览器 <strong><code>IndexedDB</code></strong> 存储本地操作，网络恢复后自动与服务器同步，Yjs 生态对此有完善支持</li><li><strong>撤销/重做</strong>：协同环境下更复杂。Yjs 提供内置 <strong><code>UndoManager</code></strong> 管理本地操作历史；全局范围的撤销需要更复杂的策略设计</li></ul><h3 id="_3-网络连接与协议选择" tabindex="-1">3. 网络连接与协议选择 <a class="header-anchor" href="#_3-网络连接与协议选择" aria-label="Permalink to &quot;3. 网络连接与协议选择&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">协议</th><th style="text-align:left;">特点</th><th style="text-align:left;">适用场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>WebSocket</strong></td><td style="text-align:left;">双向持久连接，是实时通信最常用方案</td><td style="text-align:left;">中心化协同架构，服务器转发模式</td></tr><tr><td style="text-align:left;"><strong>WebRTC</strong></td><td style="text-align:left;">点对点传输，无需中央服务器</td><td style="text-align:left;">去中心化 / 无服务器协同（Yjs + WebRTC）</td></tr></tbody></table><h3 id="_4-性能与安全优化" tabindex="-1">4. 性能与安全优化 <a class="header-anchor" href="#_4-性能与安全优化" aria-label="Permalink to &quot;4. 性能与安全优化&quot;">​</a></h3><ul><li><strong>操作批处理</strong>：高频事件（连续打字）会产生大量微小操作，合并成批次发送可大幅降低网络和计算开销</li><li><strong>传输安全</strong>：生产环境必须使用 <strong>WSS（WebSocket Secure）</strong> 或 HTTPS，对通信内容加密</li><li><strong>权限校验</strong>：服务端需进行严格的身份验证和权限校验，防止未授权访问</li></ul><blockquote><p>⚠️ <strong>注意</strong>：协同系统中安全往往被忽视——确保 WebSocket 握手时验证身份 token，并在每次操作时校验用户对该文档的读写权限。</p></blockquote><hr>`,43)])])}const x=e(s,[["render",o]]);export{p as __pageData,x as default};
